// ============================================================
// NOEUD 2 — Initialiser le batch (CORRIGÉ V2 - Défensif & Thread-Safe)
// ============================================================
const inputs = $input.all();
const executionId = $execution.id;
const globalData = $getWorkflowStaticData('node');

const now = new Date();
const hex = Array.from({ length: 6 }, () => Math.floor(Math.random() * 16).toString(16).toUpperCase()).join("");
const batch_id = `BATCH-${now.getFullYear()}-${hex}`;
let correlation_id = `CORR-${now.getFullYear()}-${hex}`;
let incoming_message_id = null;

let batch = [];
let fatalError = null;
let errorCode = "INVALID_BATCH";

try {
  if (inputs.length !== 1) throw new Error(`1 seul message batch attendu, ${inputs.length} reçus`);
  const input = inputs[0].json;

  correlation_id = input.correlation_id || input.message_id || correlation_id;
  incoming_message_id = input.message_id || null;

  // --- Extraire le batch ---
  if (input.action === 'PROCESS_BATCH' && Array.isArray(input.payload?.batch)) {
    batch = input.payload.batch;
  } else if (Array.isArray(input.payload?.batch)) {
    batch = input.payload.batch;
  } else if (Array.isArray(input.batch)) {
    batch = input.batch;
  } else if (Array.isArray(input)) {
    batch = input;
  } else {
    throw new Error("Aucun batch (array) trouvé dans l'entrée");
  }

  if (batch.length === 0) throw new Error("Le batch est vide (EMPTY_BATCH)");

  for (let i = 0; i < batch.length; i++) {
    if (!batch[i] || typeof batch[i] !== "object" || Array.isArray(batch[i])) {
      throw new Error(`batch[${i}] invalide : objet JSON attendu`);
    }
  }

  // --- Vérification multi-campagnes ---
  const campaignIds = [...new Set(batch.map(item => item?.strategic?.campaign?.campaign_id).filter(v => v !== undefined && v !== null && v !== ""))];
  if (campaignIds.length > 1) {
    errorCode = "MULTIPLE_CAMPAIGN_IDS";
    throw new Error(`Plusieurs campaign_id détectés (${campaignIds.join(", ")})`);
  }

} catch (err) {
  // 🚨 PATTERN DÉFENSIF : Création de la Pilule Empoisonnée au lieu de crasher
  fatalError = err.message;
  batch = [{
    _fatal_batch_error: true,
    _error_code: errorCode,
    _error_message: fatalError,
    strategic: { request_id: "BATCH-REJECTED" } // Pour éviter d'autres erreurs null pointer
  }];
}

// Initialisation Thread-Safe pour l'accumulateur
if (!globalData[executionId]) {
  globalData[executionId] = { results: [], accepted: 0, rejected: 0 };
}
globalData[executionId].batch_id = batch_id;
globalData[executionId].correlation_id = correlation_id;
globalData[executionId].incoming_message_id = incoming_message_id;
globalData[executionId].total = batch.length; // Sera 1 pour la pilule empoisonnée

return [{
  json: {
    batch_id,
    correlation_id,
    incoming_message_id,
    total: batch.length,
    batch,
    timestamp: now.toISOString(),
    batch_meta: {
      campaign_id: fatalError ? null : (batch[0]?.strategic?.campaign?.campaign_id || null)
    }
  }
}];

// Préparer le log BATCH_RECEIVED pour le LogService
const data = $input.first().json;
return [{
  json: {
    agent: 'INGESTION_AGENT',
    event_type: 'BATCH_RECEIVED',
    message: `Batch reçu: ${data.total} diffusion(s), batch_id=${data.batch_id}`,
    job_id: '',
    correlation_id: data.correlation_id
  }
}];

// ============================================================
// NOEUD 5 — Éclater le batch en items individuels
// ============================================================
// Lit le batch depuis le noeud 'Initialiser le batch',
// retourne N items (1 par diffusion), chacun enrichi des métadonnées.
// ============================================================

const initData = $('Initialiser le batch').first().json;
const batch = initData.batch;
const batch_id = initData.batch_id;
const correlation_id = initData.correlation_id;

return batch.map((item, index) => ({
  json: {
    ...item,
    _batch_id: batch_id,
    _correlation_id: correlation_id,
    _item_index: index
  }
}));

// ============================================================
// NOEUD 6 — Validation & Normalisation
// ============================================================

const item = $input.first().json;
const batch_id = item._batch_id;
const _correlation_id = item._correlation_id;
const _item_index = item._item_index;

function fail(code, msg) {
  return [{
    json: {
      _struct_valid: false,
      batch_id,
      _correlation_id,
      _item_index,
      _result: {
        tenant_id: item.tenant_id,
        request_id: item.strategic?.request_id || `ITEM-${_item_index}`,
        status: 'REJECTED_SCHEMA',
        error_code: code,
        error_message: msg,
        job_id: null
      },
      _log: {
        agent: 'INGESTION_AGENT',
        event_type: 'REJECTED_SCHEMA',
        message: `Rejet structurel: ${msg} (index=${_item_index})`,
        job_id: '',
        correlation_id: _correlation_id
      }
    }
  }];
}

// 🚨 INTERCEPTION DE LA PILULE EMPOISONNÉE (Erreur globale du batch)
if (item._fatal_batch_error === true) {
  return fail(item._error_code, item._error_message);
}

// --- Suite normale des validations ---
if (!item.strategic || typeof item.strategic !== 'object') {
  return fail('MISSING_STRATEGIC', 'Bloc strategic absent ou non-objet');
}
if (item.payload === undefined || item.payload === null || typeof item.payload !== 'object' || Array.isArray(item.payload)) {
  return fail('MISSING_PAYLOAD', 'Bloc payload absent, null, ou type incorrect');
}

const s = item.strategic;

if (!s.request_id || typeof s.request_id !== 'string' || s.request_id.trim() === '') {
  return fail('MISSING_REQUEST_ID', 'request_id absent ou vide');
}
if (!s.source_agent || typeof s.source_agent !== 'string') {
  return fail('MISSING_SOURCE_AGENT', 'source_agent absent');
}
if (!s.diffusion_type || typeof s.diffusion_type !== 'string') {
  return fail('MISSING_DIFFUSION_TYPE', 'diffusion_type absent');
}
if (!s.funnel_stage || typeof s.funnel_stage !== 'string') {
  return fail('MISSING_FUNNEL_STAGE', 'funnel_stage absent');
}

if (!s.campaign || typeof s.campaign !== 'object') {
  return fail('MISSING_CAMPAIGN', 'Bloc campaign absent');
}
if (s.campaign.campaign_id === undefined || s.campaign.campaign_id === null || s.campaign.campaign_id === '') {
  return fail('MISSING_CAMPAIGN_ID', 'campaign_id absent');
}
if (!s.client || typeof s.client !== 'object') {
  return fail('MISSING_CLIENT', 'Bloc client absent');
}
if (s.client.client_id === undefined || s.client.client_id === null || s.client.client_id === '') {
  return fail('MISSING_CLIENT_ID', 'client_id absent');
}
if (!s.channel || typeof s.channel !== 'object') {
  return fail('MISSING_CHANNEL', 'Bloc channel absent');
}
if (!s.channel.channel_name || typeof s.channel.channel_name !== 'string') {
  return fail('MISSING_CHANNEL_NAME', 'channel_name absent');
}
if (!s.channel.credential_ref || typeof s.channel.credential_ref !== 'string') {
  return fail('MISSING_CREDENTIAL_REF', 'credential_ref absent dans channel');
}
if (!s.budget || typeof s.budget !== 'object') {
  return fail('MISSING_BUDGET', 'Bloc budget absent');
}
if (!s.compliance || typeof s.compliance !== 'object') {
  return fail('MISSING_COMPLIANCE', 'Bloc compliance absent');
}

const request_id = s.request_id.trim();
const source_agent = s.source_agent.trim().toUpperCase();
const diffusion_type = s.diffusion_type.trim().toUpperCase();
const funnel_stage = s.funnel_stage.trim().toUpperCase();
const channel_name = s.channel.channel_name.trim().toUpperCase();
const credential_ref = s.channel.credential_ref.trim();
const client_id = s.client.client_id;
const campaign_id = s.campaign.campaign_id;
const campaign_name = s.campaign.campaign_name || '';
const diffusion_id = s.diffusion_id || null;

let scheduled_at = null;
let timezone = 'Africa/Casablanca';

if (s.schedule && s.schedule.publish_at) {
  const parsedDate = new Date(s.schedule.publish_at);
  if (isNaN(parsedDate.getTime())) {
    return fail('INVALID_SCHEDULE_DATE', 'publish_at invalide');
  }
  scheduled_at = parsedDate.toISOString();
  timezone = (s.schedule.timezone || 'Africa/Casablanca').trim();
}

const budget_amount = (s.budget.amount !== undefined && s.budget.amount !== null)
  ? Number(s.budget.amount)
  : null;

const budget_currency = (s.budget.currency || '').trim().toUpperCase();
const compliance_validated = s.compliance.validated === true;
const payload = item.payload;

return [{
  json: {
    _struct_valid: true,
    batch_id,
    _correlation_id,
    _item_index,
    request_id,
    diffusion_id,
    source_agent,
    diffusion_type,
    funnel_stage,
    channel_name,
    credential_ref,
    client_id,
    campaign_id,
    campaign_name,
    scheduled_at,
    timezone,
    budget_amount,
    budget_currency,
    compliance_validated,
    payload,
    tenant_id: item.tenant_id,
    action: 'FIND_BY_REQUEST_ID'
  }
}];

// ============================================================
// NOEUD 10 — Analyser Idempotence + Préparer suite
// ============================================================
// Lit le résultat enrichi du JobService FIND_BY_REQUEST_ID.
// Si doublon : prépare le résultat DUPLICATE_IGNORED.
// Si nouveau : prépare l'appel ChannelConfigService.
// ============================================================

const item = $input.first().json;
const isDuplicate = item.exists === true;

if (isDuplicate) {
  return [{
    json: {
      ...item,
      _is_duplicate: true,
      _existing_job_id: item.existing_job_id || '',
      _existing_status: item.existing_status || '',
      _result: {
        tenant_id: item.tenant_id,
        request_id: item.request_id,
        status: 'DUPLICATE_IGNORED',
        error_code: 'DUPLICATE_REQUEST_ID',
        error_message: `request_id déjà existant, job ${item.existing_job_id} retourné`,
        job_id: item.existing_job_id || null
      },
      _log: {
        agent: 'INGESTION_AGENT',
        event_type: 'DUPLICATE_IGNORED',
        message: `${item.request_id} déjà existant, job ${item.existing_job_id} retourné`,
        job_id: item.existing_job_id || '',
        correlation_id: item._correlation_id
      }
    }
  }];
}

// --- NOUVEAU : préparer pour ChannelConfigService ---
return [{
  json: {
    ...item,
    _is_duplicate: false,
    action: 'VALIDATE_CHANNEL'
  }
}];

// ============================================================
// NOEUD 13 — Analyser Canal + Préparer appel Credential
// ============================================================

const item = $input.first().json;
const channelSupported = item.supported === true;

return [{
  json: {
    ...item,
    _channel_supported: channelSupported,
    _channel_result: {
      supported: item.supported,
      channel_name: item.channel_name
    },
    action: 'VALIDATE_CREDENTIAL',
    credential_ref: item.credential_ref
  }
}];

// ============================================================
// NOEUD 15 — Validation Métier Complète
// ============================================================

const item = $input.first().json;

function fail(code, msg) {
  return [{
    json: {
      ...item,
      _business_valid: false,
      _result: {
        tenant_id: item.tenant_id,
        request_id: item.request_id,
        status: 'REJECTED_BUSINESS',
        error_code: code,
        error_message: msg,
        job_id: null
      },
      _log: {
        agent: 'INGESTION_AGENT',
        event_type: 'REJECTED_BUSINESS',
        message: msg,
        job_id: '',
        correlation_id: item._correlation_id
      }
    }
  }];
}

// 1. Canal supporté
if (item._channel_supported !== true) {
  return fail('UNSUPPORTED_CHANNEL', `Canal non supporté: ${item.channel_name}`);
}

// 2. Credential valide
if (item.valid !== true) {
  return fail(
    item.error_code || 'INVALID_CREDENTIAL',
    item.error_message || `Credential invalide: ${item.credential_ref}`
  );
}

// 3. source_agent autorisé
const allowedAgents = ['AGENT_ADS', 'AGENT_MARKETING', 'AGENT_COMMUNITY', 'AGENT_MAILING'];
if (!allowedAgents.includes(item.source_agent)) {
  return fail('INVALID_SOURCE_AGENT', `source_agent invalide: ${item.source_agent}`);
}

// 4. funnel_stage autorisé
const allowedFunnelStages = ['TOFU', 'MOFU', 'BOFU'];
if (!allowedFunnelStages.includes(item.funnel_stage)) {
  return fail('INVALID_FUNNEL_STAGE', `funnel_stage invalide: ${item.funnel_stage}`);
}

// 5. diffusion_type autorisé
const allowedDiffusionTypes = ['PAID', 'ORGANIC'];
if (!allowedDiffusionTypes.includes(item.diffusion_type)) {
  return fail('INVALID_DIFFUSION_TYPE', `diffusion_type invalide: ${item.diffusion_type}`);
}

// 6. conformité obligatoire
if (item.compliance_validated !== true) {
  return fail('COMPLIANCE_NOT_VALIDATED', 'Le contenu n’a pas été validé côté conformité');
}

// 7. budget obligatoire pour PAID
if (item.diffusion_type === 'PAID') {
  if (item.budget_amount === null || isNaN(item.budget_amount) || item.budget_amount <= 0) {
    return fail('INVALID_BUDGET', 'Budget obligatoire et strictement positif pour une diffusion PAID');
  }
  if (!item.budget_currency || item.budget_currency.trim() === '') {
    return fail('MISSING_BUDGET_CURRENCY', 'Devise obligatoire pour une diffusion PAID');
  }
}

// 8. payload minimal
if (!item.payload || typeof item.payload !== 'object' || Array.isArray(item.payload)) {
  return fail('INVALID_PAYLOAD', 'Payload invalide');
}

// Exemple simple : pour content marketing
if (!item.payload.content || typeof item.payload.content !== 'object') {
  return fail('MISSING_CONTENT', 'Bloc content absent dans payload');
}

// 9. OK
return [{
  json: {
    ...item,
    _business_valid: true,
    action: 'CREATE_JOB'
  }
}];

const item = $input.first().json;

return [{
  json: {
    ...item,
    _result: {
      tenant_id: item.tenant_id,
      request_id: item.request_id,
      status: item.status || 'JOB_CREATED',
      error_code: null,
      error_message: null,
      job_id: item.job_id || null
    },
    _log: {
      agent: 'INGESTION_AGENT',
      event_type: 'JOB_CREATED',
      message: `Job créé avec succès: ${item.job_id}`,
      job_id: item.job_id || '',
      correlation_id: item._correlation_id
    }
  }
}];

// ============================================================
// NOEUD — Préparer Log Item
// ============================================================

const item = $input.first().json;

if (!item._log) {
  throw new Error("IngestionAgent — _log introuvable dans Préparer Log Item");
}

return [{
  json: {
    ...item,                  // on conserve tout le contexte
    ...item._log              // on expose aussi les champs attendus par LogService
  }
}];

// ============================================================
// NOEUD — Stocker résultat (CORRIGÉ V2 - Isolation par exécution)
// ============================================================

const item = $input.first().json;
const result = item._result;

if (!result) {
  throw new Error("IngestionAgent — _result introuvable dans Stocker résultat");
}

// 1. On récupère l'ID unique de cette exécution précise
const executionId = $execution.id;
const globalData = $getWorkflowStaticData('node');

// 2. On crée un tiroir isolé pour cette exécution si ce n'est pas fait
if (!globalData[executionId]) {
  globalData[executionId] = {
    results: [],
    accepted: 0,
    rejected: 0
  };
}

const currentRunData = globalData[executionId];

// 3. On range le résultat dans ce tiroir spécifique
currentRunData.results.push(result);

if (
  result.status === 'REJECTED_SCHEMA' ||
  result.status === 'REJECTED_BUSINESS' ||
  result.status === 'DUPLICATE_IGNORED'
) {
  currentRunData.rejected += 1;
} else {
  currentRunData.accepted += 1;
}

// On retourne un JSON pour visualiser que tout s'est bien passé
return [{ 
  json: { 
    message: "Résultat isolé et stocké avec succès",
    execution_id: executionId
  } 
}];

// ============================================================
// NOEUD — Construire ACK (CORRIGÉ V2)
// ============================================================

const executionId = $execution.id;
const globalData = $getWorkflowStaticData('node');

// 1. On récupère les données isolées de NOTRE exécution
const runData = globalData[executionId] || { results: [], accepted: 0, rejected: 0 };

// 2. Nettoyage de la mémoire (Très important pour ne pas saturer le serveur n8n)
delete globalData[executionId];

// 3. Détermination du statut global du batch
let batchStatus = "PARTIAL_SUCCESS";
if (runData.rejected === 0 && runData.accepted > 0) batchStatus = "SUCCESS";
if (runData.accepted === 0 && runData.rejected > 0) batchStatus = "FAILED";
if (runData.accepted === 0 && runData.rejected === 0) batchStatus = "EMPTY";

// 4. Construction de la réponse finale V2
return [{
  json: {
    status: batchStatus,
    summary: {
      accepted: runData.accepted,
      rejected: runData.rejected,
      total: runData.accepted + runData.rejected
    },
    results: runData.results
  }
}];
